// Package gen defines the Generator interface and supporting types that
// components implement to produce generated code.
package gen

import (
	"fmt"
	"path/filepath"
	"strings"

	"github.com/jsell-rh/stego/internal/types"
)

// Header is the required comment header for all generated files.
const Header = "// Code generated by stego. DO NOT EDIT."

// Generator is the interface that components implement to produce generated
// code. Each component is a Go package that exports a Generator. Alongside
// its files, each generator returns a Wiring struct that the compiler uses
// to assemble shared files (cmd/main.go, go.mod, etc.).
type Generator interface {
	Generate(ctx Context) ([]File, *Wiring, error)
}

// Context carries resolved information that generators need to produce code.
type Context struct {
	// Conventions from the archetype (layout, error handling, logging, etc.).
	Conventions types.Convention

	// Entities defined in the service declaration.
	Entities []types.Entity

	// Collections from the service declaration.
	Collections []types.Collection

	// SlotBindings from the service declaration, in declaration order.
	// The ordering is significant: generators and the assembler must iterate
	// bindings in the same order to agree on constructor parameter positions.
	SlotBindings []types.SlotDeclaration

	// ModuleName is the Go module path (e.g. "github.com/myorg/user-service").
	// Generators use this to construct full import paths for cross-package
	// references (e.g. importing the slots package from handler code).
	ModuleName string

	// SlotsPackage is the relative import path (under ModuleName) for the
	// generated slot operators package (e.g. "internal/slots"). Empty if
	// no slots are configured.
	SlotsPackage string

	// ComponentConfig holds the component-specific config values resolved
	// from defaults and service-level overrides.
	ComponentConfig map[string]any

	// OutputNamespace is the component's declared output namespace
	// (e.g. "internal/api"). Generators can only write files under it.
	OutputNamespace string

	// OutDirName is the name of the output directory relative to the project
	// root (e.g. "out"). Generators use this when constructing full import
	// paths for generated packages within the output directory. With go.mod
	// at the project root, import paths for generated packages must include
	// this prefix (e.g. "<module>/out/internal/slots" instead of
	// "<module>/internal/slots"). Empty string means no prefix is added.
	OutDirName string

	// AuthPackage is the full import path for the auth middleware package
	// (e.g. "github.com/myorg/svc/out/internal/auth"). Generators use this
	// to import auth.IdentityFromContext for extracting caller identity from
	// the request context. Empty if no auth component is resolved.
	AuthPackage string

	// BasePath is prepended to all collection-derived routes (e.g.
	// "/api/hyperfleet/v1"). Empty string means paths are served from root.
	BasePath string

	// ServiceName is the service declaration's name (e.g. "hyperfleet-api").
	// Generators use this to derive error code prefixes and other
	// service-scoped identifiers.
	ServiceName string

	// ErrorTypeBase is an optional URI prefix for RFC 9457 error type URIs
	// (e.g. "https://api.hyperfleet.io/errors/"). When set, error type URIs
	// are constructed as ErrorTypeBase + error-slug. When empty, error types
	// use "about:blank" per RFC 9457.
	ErrorTypeBase string
}

// File represents a single generated output file.
type File struct {
	// Path is relative to the project output root (e.g. "internal/api/handler.go").
	Path string

	// Content is the file body, excluding the generated header.
	Content []byte
}

// Bytes returns the complete file content ready to be written to disk.
// For Go source files and go.mod, it prepends the required generated-file
// header using Go comment syntax. For non-Go files (JSON, YAML, etc.), the
// content is returned as-is because Go-comment syntax would make them
// unparseable by their format's standard tooling.
func (f File) Bytes() []byte {
	ext := filepath.Ext(f.Path)
	base := filepath.Base(f.Path)
	if ext == ".go" || base == "go.mod" {
		return []byte(Header + "\n\n" + string(f.Content))
	}
	return f.Content
}

// Wiring captures what a component needs wired into shared generated files
// (e.g. cmd/main.go, go.mod).
type Wiring struct {
	// Imports lists Go import paths the component needs in main.go.
	Imports []string

	// Constructors lists constructor call expressions for main.go assembly.
	// Each entry is a code fragment like "api.NewUserHandler(userService, ...)".
	Constructors []string

	// ConstructorCollections maps constructor index to the collection name
	// it handles. The assembler uses this to inject slot operators into the
	// correct handler constructors, replacing convention-based name matching
	// (e.g. inferring collection from "New<Collection>Handler" naming convention).
	// Only handler constructors that should receive slot operator injection
	// need entries here; non-handler constructors are simply omitted.
	ConstructorCollections map[int]string

	// Routes lists route registration expressions for main.go assembly.
	// Each entry is a code fragment like "mux.Handle(\"/users\", userHandler)".
	Routes []string

	// MiddlewareConstructor, if non-nil, indicates which constructor index
	// produces an auth middleware. The assembler uses this to wrap the mux
	// with the middleware, replacing fragile string matching on constructor
	// expressions (e.g. checking for "AuthMiddleware" substring).
	MiddlewareConstructor *int

	// MiddlewareWrapExpr is a format string that produces the expression
	// to wrap the HTTP handler with middleware. It must contain exactly two
	// %s verbs: the first is replaced with the middleware variable name
	// (after disambiguation), the second with the handler variable
	// (typically "mux").
	// Example: "%s(%s)" for function-type middleware → "authMiddleware(mux)".
	// Example: "%s.Handler(%s)" for struct-type middleware → "authMiddleware.Handler(mux)".
	// Required when MiddlewareConstructor is non-nil.
	MiddlewareWrapExpr string

	// NeedsDB indicates whether this component requires a database connection.
	// The assembler uses this to determine whether to emit database setup code
	// in main.go, replacing fragile string matching on constructor expressions.
	// When DBBackend is set, NeedsDB is implied and does not need to be set
	// separately.
	NeedsDB bool

	// DBBackend specifies which database driver the assembler should use in
	// the generated main.go. "gorm" emits gorm.Open with the postgres driver;
	// "sql" (or empty with NeedsDB=true) emits sql.Open for raw database/sql.
	// When set, NeedsDB is implied.
	DBBackend string

	// GoModRequires lists module dependencies for the generated go.mod.
	// Keys are module paths (e.g. "gorm.io/gorm"), values are version
	// strings (e.g. "v1.25.12"). The assembler collects these from all
	// component wirings and emits a require block.
	GoModRequires map[string]string

	// ConstructorDeps maps constructor index to the list of variable names
	// (from other wirings' constructors) that this constructor references in
	// its expression. The assembler uses this to topologically sort constructor
	// declarations so that referenced variables are declared before referencing
	// ones. Variable names here correspond to the raw variable name derived
	// from the target constructor's expression via rawConstructorVarName
	// (e.g. "store" for storage.NewStore(db)).
	ConstructorDeps map[int][]string

	// PostDBCalls lists Go expressions that should be called after database
	// setup and before constructor declarations in the generated main.go.
	// Each expression must return an error (e.g. "storage.Migrate(db)").
	// The assembler wraps each call in error handling:
	//   if err := <expr>; err != nil { log.Fatal(err) }
	PostDBCalls []string
}

// ValidateNamespace checks that every file path in files is under the given
// namespace prefix. Namespace is a slash-separated relative path
// (e.g. "internal/api"). Returns an error listing all violations.
func ValidateNamespace(namespace string, files []File) error {
	ns := filepath.ToSlash(filepath.Clean(namespace))
	if ns == "." || ns == "" {
		return fmt.Errorf("namespace must be a non-empty relative path, got %q", namespace)
	}

	prefix := ns + "/"

	var violations []string
	for _, f := range files {
		clean := filepath.ToSlash(filepath.Clean(f.Path))
		// The path must either equal the namespace (a file named exactly the
		// namespace, unlikely but valid) or start with namespace + "/".
		if clean != ns && !strings.HasPrefix(clean, prefix) {
			violations = append(violations, f.Path)
		}
	}

	if len(violations) > 0 {
		return &NamespaceError{
			Namespace:  namespace,
			Violations: violations,
		}
	}
	return nil
}

// NamespaceError reports files that fall outside a component's declared
// output namespace.
type NamespaceError struct {
	Namespace  string
	Violations []string
}

func (e *NamespaceError) Error() string {
	return fmt.Sprintf("files outside namespace %q: %s",
		e.Namespace, strings.Join(e.Violations, ", "))
}
